import java.io.*;
import java.util.*;

public class Main {
    private static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c;
            do {
                c = readByte();
                if (c == -1) return Long.MIN_VALUE; // signal EOF
            } while (c <= ' ');
            boolean neg = false;
            if (c == '-' ) { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder sb = new StringBuilder();
        long tLong = fs.nextLong();
        if (tLong == Long.MIN_VALUE) return; // no input
        int T = (int) tLong;
        for (int tc = 0; tc < T; tc++) {
            int N = (int) fs.nextLong();
            int M = (int) fs.nextLong();
            long[] F = new long[N];
            long[] C = new long[M];
            for (int i = 0; i < N; i++) F[i] = fs.nextLong();
            for (int i = 0; i < M; i++) C[i] = fs.nextLong();
            int i = 0, j = 0;
            int lastSport = 0; // 0 = football (starting channel), 1 = cricket
            long switches = 0;
            while (i < N && j < M) {
                if (F[i] < C[j]) {
                    if (lastSport != 0) switches++;
                    lastSport = 0;
                    i++;
                } else {
                    if (lastSport != 1) switches++;
                    lastSport = 1;
                    j++;
                }
            }
            while (i < N) {
                if (lastSport != 0) switches++;
                lastSport = 0;
                i++;
            }
            while (j < M) {
                if (lastSport != 1) switches++;
                lastSport = 1;
                j++;
            }
            sb.append(switches).append('\n');
        }
        System.out.print(sb.toString());
    }
}

